mapper.select:
SELECT

FROM `record`
WHERE id = #{id}
  AND user_id = #{userId}
LIMIT 1

mapper.delete:
DELETE FROM `record`
WHERE id = #{id}
  AND user_id = #{userId}
  AND status = 'DRAFT'

mapper.update:
UPDATE `record`
SET
    status = 'SEALED',
    sealed_at = #{sealedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}
  AND user_id = #{userId}
  AND status = 'DRAFT'

mapper.select:
SELECT COUNT(1)
FROM `record`
WHERE user_id = #{userId}

    AND status = #{status}


    AND record_type = #{recordType}

SELECT

FROM `record`
WHERE user_id = #{userId}

    AND status = #{status}


    AND record_type = #{recordType}

ORDER BY created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT

FROM `record`
WHERE user_id = #{userId}
  AND status = 'UNLOCKED'
ORDER BY unlocked_at DESC, id DESC
LIMIT #{pageSize} OFFSET #{offset}
